// // This module implements an active-high isolation gate. When SLEEP is high, the output X follows the input A; otherwise, X is always LOW.
module top_module(
    X    ,
    A    ,
    SLEEP
);// Module ports
    output X    ;
    input  A    ;
    input  SLEEP;

    // Local signals
    wire sleepn;

    //  Name  Output  Other arguments
    not not0 (sleepn, SLEEP          );
    and and0 (X     , A, sleepn      );

endmodule
